// k6-llm-load-test.js
// Run: k6 run --vus 20 --duration 5m k6-llm-load-test.js
import http from 'k6/http';
import { check, sleep } from 'k6';
import { Rate, Trend, Counter } from 'k6/metrics';

// Custom metrics
const ttft = new Trend('llm_ttft_ms', true);           // time-to-first-token
const tokenRate = new Rate('llm_token_success_rate');   // success rate
const totalTokens = new Counter('llm_total_tokens');    // cumulative tokens
const rateLimitErrors = new Counter('llm_rate_limit_429s');

export const options = {
  stages: [
    { duration: '1m', target: 10 },   // ramp up to 10 VUs
    { duration: '3m', target: 50 },   // ramp to 50 VUs
    { duration: '2m', target: 50 },   // sustain at 50 VUs
    { duration: '1m', target: 0 },    // ramp down
  ],
  thresholds: {
    // SLA: 95% of requests must complete in under 3 seconds
    'http_req_duration': ['p(95)<3000'],
    // Token success rate must stay above 99%
    'llm_token_success_rate': ['rate>0.99'],
    // Rate limit errors must be below 1%
